import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"紹介: ローカル AI ゲートウェイ | Antigravity Manager","description":"Antigravity Manager のコアポジショニングを理解します。デスクトップ版とローカル HTTP ゲートウェイを提供し、複数のプロトコルエンドポイントとアカウントプールスケジューリングをサポートし、ローカルリバースプロキシを迅速に開始し、一般的な設定エラーを回避するのに役立ちます。","frontmatter":{"title":"紹介: ローカル AI ゲートウェイ | Antigravity Manager","sidebarTitle":"ローカル AI ゲートウェイとは","subtitle":"Antigravity Tools とは：「アカウント + プロトコル」でローカル AI ゲートウェイを作る","description":"Antigravity Manager のコアポジショニングを理解します。デスクトップ版とローカル HTTP ゲートウェイを提供し、複数のプロトコルエンドポイントとアカウントプールスケジューリングをサポートし、ローカルリバースプロキシを迅速に開始し、一般的な設定エラーを回避するのに役立ちます。","tags":["入門","概念","ローカルゲートウェイ","API Proxy"],"prerequisite":[],"order":1},"headers":[],"relativePath":"ja/lbjlaq/Antigravity-Manager/start/getting-started/index.md","filePath":"ja/lbjlaq/Antigravity-Manager/start/getting-started/index.md"}'),l={name:"ja/lbjlaq/Antigravity-Manager/start/getting-started/index.md"};function i(d,t,n,s,c,h){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="antigravity-tools-とは-「アカウント-プロトコル」でローカル-ai-ゲートウェイを作る" tabindex="-1">Antigravity Tools とは：「アカウント + プロトコル」でローカル AI ゲートウェイを作る <a class="header-anchor" href="#antigravity-tools-とは-「アカウント-プロトコル」でローカル-ai-ゲートウェイを作る" aria-label="Permalink to &quot;Antigravity Tools とは：「アカウント + プロトコル」でローカル AI ゲートウェイを作る&quot;">​</a></h1><p>多くの AI クライアント/SDK の導入の敷居は、「API を呼び出せるかどうか」ではなく、「どのプロトコルに接続するか、複数のアカウントをどう管理するか、失敗をどう自動回復させるか」にあります。Antigravity Tools はこの 3 つをローカルゲートウェイに収束しようとします。</p><h2 id="antigravity-tools-とは" tabindex="-1">Antigravity Tools とは？ <a class="header-anchor" href="#antigravity-tools-とは" aria-label="Permalink to &quot;Antigravity Tools とは？&quot;">​</a></h2><p><strong>Antigravity Tools</strong> はデスクトップアプリケーションです。GUI でアカウントと設定を管理し、ローカルマシンで HTTP リバースプロキシサービスを起動し、異なるベンダー/プロトコルのリクエストを統一的に上流に転送し、応答をクライアントが慣れ親しんだ形式に変換して戻します。</p><h2 id="学習後にできること" tabindex="-1">学習後にできること <a class="header-anchor" href="#学習後にできること" aria-label="Permalink to &quot;学習後にできること&quot;">​</a></h2><ul><li>Antigravity Tools がどのような問題を解決するか（また、何を解決しないか）を明確に言える</li><li>コア構成を認識する：GUI、アカウントプール、HTTP リバースプロキシゲートウェイ、プロトコルアダプタ</li><li>デフォルトのセキュリティ境界（127.0.0.1、ポート、認証モード）と、いつ変更する必要があるかを理解する</li><li>次にどの章に行くべきかを知る：インストール、アカウント追加、リバースプロキシ起動、クライアント接続</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><p>次のトラブルに遭遇したかもしれません：</p><ul><li>同じクライアントで OpenAI/Anthropic/Gemini の 3 種類のプロトコルをサポートする必要があり、設定が頻繁に乱れる</li><li>複数のアカウントがあるが、切り替え、ローテーション、レート制限リトライはすべて手動</li><li>リクエストが失敗した場合、「アカウント無効」か「上流レート制限/容量枯渇」かはログを見て推測するしかない</li></ul><p>Antigravity Tools の目標は、これらの「雑多な作業」をローカルゲートウェイに入れ、クライアント/SDK をできるだけ 1 つのことだけ気にさせる：リクエストをローカルに送ること。</p><h2 id="コアアイデア" tabindex="-1">コアアイデア <a class="header-anchor" href="#コアアイデア" aria-label="Permalink to &quot;コアアイデア&quot;">​</a></h2><p>これをローカルの「AI スケジューリングゲートウェイ」と理解でき、3 層で構成されています：</p><ol><li>GUI（デスクトップアプリケーション）</li></ol><ul><li>アカウント、設定、監視、統計を管理する責任があります。</li><li>メインページには：Dashboard、Accounts、API Proxy、Monitor、Token Stats、Settings が含まれます。</li></ul><ol start="2"><li>HTTP リバースプロキシサービス（Axum Server）</li></ol><ul><li>複数のプロトコルエンドポイントを外部に公開し、リクエストを対応するハンドラに転送する責任があります。</li><li>リバースプロキシサービスは認証、ミドルウェア監視、CORS、Trace などのレイヤをマウントします。</li></ul><ol start="3"><li>アカウントプールとスケジューリング（TokenManager など）</li></ol><ul><li>ローカルアカウントプールから使用可能なアカウントを選択し、必要に応じて token を更新し、ローテーションと自己回復を行う責任があります。</li></ul><div class="info custom-block"><p class="custom-block-title">「ローカルゲートウェイ」とはどういう意味ですか？</p><p>ここでの「ローカル」は文字通りです：サービスはあなたのマシンで実行され、クライアント（Claude Code、OpenAI SDK、各種サードパーティクライアント）は Base URL を <code>http://127.0.0.1:&lt;port&gt;</code> にポイントし、リクエストは最初にローカルマシンに到着し、Antigravity Tools によって上流に転送されます。</p></div><h2 id="どのようなエンドポイントを提供するか" tabindex="-1">どのようなエンドポイントを提供するか <a class="header-anchor" href="#どのようなエンドポイントを提供するか" aria-label="Permalink to &quot;どのようなエンドポイントを提供するか&quot;">​</a></h2><p>リバースプロキシサービスは Router で複数のプロトコルエンドポイントを登録し、まずこれらの「入口」を覚えてください：</p><ul><li>OpenAI 互換：<code>/v1/chat/completions</code>、<code>/v1/completions</code>、<code>/v1/responses</code>、<code>/v1/models</code></li><li>Anthropic 互換：<code>/v1/messages</code>、<code>/v1/messages/count_tokens</code></li><li>Gemini ネイティブ：<code>/v1beta/models</code>、<code>/v1beta/models/:model</code>、<code>/v1beta/models/:model/countTokens</code></li><li>ヘルスチェック：<code>GET /healthz</code></li></ul><p>クライアントがこれらのいずれかのプロトコルに接続できる場合、理論的には「Base URL を変更」することで、リクエストをこのローカルゲートウェイに導くことができます。</p><h2 id="デフォルトのセキュリティ境界-スキップしないでください" tabindex="-1">デフォルトのセキュリティ境界（スキップしないでください） <a class="header-anchor" href="#デフォルトのセキュリティ境界-スキップしないでください" aria-label="Permalink to &quot;デフォルトのセキュリティ境界（スキップしないでください）&quot;">​</a></h2><p>この種の「ローカルリバースプロキシ」の最大の落とし穴は、機能が不足しているのではなく、誤って外部に公開してしまうことです。</p><p>まずデフォルト値を覚えてください（すべてデフォルト設定から来ています）：</p><ul><li>デフォルトポート：<code>8045</code></li><li>デフォルトローカルアクセスのみ：<code>allow_lan_access=false</code>、監視アドレスは <code>127.0.0.1</code></li><li>デフォルト認証モード：<code>auth_mode=off</code>（クライアントに key を要求しない）</li><li>デフォルトで <code>sk-...</code> 形式の <code>api_key</code> を生成（認証が必要な場合に使用）</li></ul><div class="warning custom-block"><p class="custom-block-title">いつ認証を有効にする必要がありますか？</p><p>LAN アクセスを有効にしたら（<code>allow_lan_access=true</code>、監視アドレスが <code>0.0.0.0</code> になる）、同時に認証を有効にし、API Key をパスワードとして管理する必要があります。</p></div><h2 id="いつ-antigravity-tools-を使用するか" tabindex="-1">いつ Antigravity Tools を使用するか <a class="header-anchor" href="#いつ-antigravity-tools-を使用するか" aria-label="Permalink to &quot;いつ Antigravity Tools を使用するか&quot;">​</a></h2><p>このようなシナリオに適しています：</p><ul><li>複数の AI クライアント/SDK があり、1 つの Base URL で統一したい</li><li>異なるプロトコル（OpenAI/Anthropic/Gemini）を同じ「ローカル出口」に収束させたい</li><li>複数のアカウントがあり、システムにローテーションと安定性処理を担当させたい</li></ul><p>「2 行のコードで公式 API を直接呼び出す」だけの場合、アカウント/プロトコルが固定されている場合、少し重いかもしれません。</p><h2 id="手順に従って進める-正しい使用順序を最初に確立する" tabindex="-1">手順に従って進める：正しい使用順序を最初に確立する <a class="header-anchor" href="#手順に従って進める-正しい使用順序を最初に確立する" aria-label="Permalink to &quot;手順に従って進める：正しい使用順序を最初に確立する&quot;">​</a></h2><p>このレッスンは詳細な設定を教えませんが、まずメインの順序を合わせ、スキップして使用して詰まらないようにします：</p><h3 id="ステップ-1-まずインストールして起動する" tabindex="-1">ステップ 1：まずインストールして起動する <a class="header-anchor" href="#ステップ-1-まずインストールして起動する" aria-label="Permalink to &quot;ステップ 1：まずインストールして起動する&quot;">​</a></h3><p><strong>なぜ</strong> デスクトップ版はアカウント管理とリバースプロキシサービスの起動を担当し、これがなければ、後続の OAuth/リバースプロキシは始まりません。</p><p>次の章で README のインストール方法に従ってインストールを完了してください。</p><p><strong>次のように表示されます</strong>：Antigravity Tools を開き、Dashboard ページが表示されます。</p><h3 id="ステップ-2-少なくとも-1-つのアカウントを追加する" tabindex="-1">ステップ 2：少なくとも 1 つのアカウントを追加する <a class="header-anchor" href="#ステップ-2-少なくとも-1-つのアカウントを追加する" aria-label="Permalink to &quot;ステップ 2：少なくとも 1 つのアカウントを追加する&quot;">​</a></h3><p><strong>なぜ</strong> リバースプロキシサービスはアカウントプールから使用可能な ID を取得して上流にリクエストを送信する必要があります。アカウントがない場合、ゲートウェイも「あなたに代わって呼び出し」できません。</p><p>「アカウント追加」の章に行き、OAuth または Refresh Token フローに従ってアカウントを追加してください。</p><p><strong>次のように表示されます</strong>：Accounts ページにアカウントが表示され、クォータ/ステータス情報が表示されます。</p><h3 id="ステップ-3-api-proxy-を起動し、-healthz-で最小限の検証を行う" tabindex="-1">ステップ 3：API Proxy を起動し、/healthz で最小限の検証を行う <a class="header-anchor" href="#ステップ-3-api-proxy-を起動し、-healthz-で最小限の検証を行う" aria-label="Permalink to &quot;ステップ 3：API Proxy を起動し、/healthz で最小限の検証を行う&quot;">​</a></h3><p><strong>なぜ</strong> 最初に <code>GET /healthz</code> で「ローカルサービスが実行中」を検証し、その後クライアントを接続すると、トラブルシューティングがはるかに簡単になります。</p><p>「ローカルリバースプロキシを起動し、最初のクライアントを接続する」の章に行ってクローズを完了してください。</p><p><strong>次のように表示されます</strong>：クライアント/SDK がローカル Base URL を通じて応答を正常に取得できます。</p><h2 id="トラブルシューティング" tabindex="-1">トラブルシューティング <a class="header-anchor" href="#トラブルシューティング" aria-label="Permalink to &quot;トラブルシューティング&quot;">​</a></h2><table tabindex="0"><thead><tr><th>シナリオ</th><th>間違ったやり方（❌）</th><th>推奨されるやり方（✓）</th></tr></thead><tbody><tr><td>携帯電話/別のコンピュータにアクセスさせたい</td><td>直接 <code>allow_lan_access=true</code> を開くが認証を設定しない</td><td>同時に認証を有効にし、まず LAN 内で <code>GET /healthz</code> を検証する</td></tr><tr><td>クライアントが 404 を返す</td><td>host/port のみ変更し、クライアントが <code>/v1</code> をどう連結するかを気にしない</td><td>最初にクライアントの base_url 連結戦略を確認し、<code>/v1</code> 接頭辞が必要かどうかを判断する</td></tr><tr><td>最初から Claude Code をトラブルシューティングする</td><td>複雑なクライアントに直接接続し、失敗後どこから調べればいいかわからない</td><td>最初に最小クローズを実行：Proxy 起動 -&gt; <code>GET /healthz</code> -&gt; その後クライアント接続</td></tr></tbody></table><h2 id="このレッスンのまとめ" tabindex="-1">このレッスンのまとめ <a class="header-anchor" href="#このレッスンのまとめ" aria-label="Permalink to &quot;このレッスンのまとめ&quot;">​</a></h2><ul><li>Antigravity Tools のポジショニングは「デスクトップ版 + ローカル HTTP リバースプロキシゲートウェイ」：GUI 管理、Axum が複数のプロトコルエンドポイントを提供</li><li>ローカルインフラとして扱う必要があります：まずインストール、次にアカウント追加、次に Proxy 起動、最後にクライアント接続</li><li>デフォルトで <code>127.0.0.1:8045</code> のみを監視します。LAN に公開する場合、必ず認証を有効にしてください</li></ul><h2 id="次のレッスン予告" tabindex="-1">次のレッスン予告 <a class="header-anchor" href="#次のレッスン予告" aria-label="Permalink to &quot;次のレッスン予告&quot;">​</a></h2><blockquote><p>次のレッスンではインストールのステップを完了します：<strong><a href="./../installation/">インストールとアップグレード：デスクトップ版最適インストールパス</a></strong>。</p><p>学びます：</p><ul><li>README に記載されている複数のインストール方法（および優先度）</li><li>アップグレード入口と一般的なシステムブロックの処理方法</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日時：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>製品ポジショニング（ローカル AI 中継局/プロトコル溝）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/README.md#L35-L77" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>35-77</td></tr><tr><td>Router エンドポイント概要（OpenAI/Claude/Gemini/healthz）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L120-L194" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>120-194</td></tr><tr><td>デフォルトポート/デフォルトローカルのみ/デフォルト key と bind address ロジック</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L291" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-291</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>GUI ページルーティング構造（Dashboard/Accounts/API Proxy/Monitor/Token Stats/Settings）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/App.tsx#L19-L48" target="_blank" rel="noreferrer"><code>src/App.tsx</code></a></td><td>19-48</td></tr></tbody></table><p><strong>重要なデフォルト値</strong>：</p><ul><li><code>ProxyConfig.port = 8045</code>：リバースプロキシサービスデフォルトポート</li><li><code>ProxyConfig.allow_lan_access = false</code>：デフォルトローカルアクセスのみ</li><li><code>ProxyAuthMode::default() = off</code>：デフォルト認証不要</li></ul></details>',55)])])}const g=a(l,[["render",i]]);export{u as __pageData,g as default};
